module top_module(
    output reg X,
    input wire A,
    input wire B,
    input wire C,
    input wire D,
    input wire VPWR,
    input wire VGND,
    input wire VPB,
    input wire VNB
);wire or_output;

    // Simple four-input OR gate implementation
    wire not_or_output = A | B | C | D;
    assign or_output = not_or_output;

    always @ (or_output) begin
        X = or_output;
    end

endmodule
